PRAGMA foreign_keys = ON;
PRAGMA journal_mode = WAL;
CREATE TABLE IF NOT EXISTS roles (id TEXT PRIMARY KEY,name TEXT NOT NULL UNIQUE,permissions TEXT NOT NULL DEFAULT '[]');
CREATE TABLE IF NOT EXISTS departments (id TEXT PRIMARY KEY,name TEXT NOT NULL UNIQUE,description TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY,name TEXT NOT NULL,email TEXT NOT NULL UNIQUE,password_hash TEXT NOT NULL,role_id TEXT NOT NULL REFERENCES roles(id),department_id TEXT REFERENCES departments(id),avatar TEXT,status TEXT NOT NULL DEFAULT 'active',last_login TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS ai_professionals (id TEXT PRIMARY KEY,name TEXT NOT NULL,avatar TEXT,department_id TEXT REFERENCES departments(id),job_title TEXT NOT NULL,specialisation TEXT NOT NULL,knowledge TEXT NOT NULL,system_prompt TEXT NOT NULL,skills TEXT NOT NULL DEFAULT '[]',tools TEXT NOT NULL DEFAULT '[]',status TEXT NOT NULL DEFAULT 'available',performance REAL NOT NULL DEFAULT 0,last_activity TEXT,current_workload INTEGER NOT NULL DEFAULT 0,is_paused INTEGER NOT NULL DEFAULT 0,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS companies (id TEXT PRIMARY KEY,name TEXT NOT NULL,country TEXT NOT NULL,industry TEXT,registration_number TEXT,renewal_date TEXT,formation_status TEXT NOT NULL DEFAULT 'prospect',owner_id TEXT REFERENCES users(id),created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS clients (id TEXT PRIMARY KEY,name TEXT NOT NULL,email TEXT NOT NULL,phone TEXT,country TEXT NOT NULL,company_id TEXT REFERENCES companies(id),consultant_id TEXT REFERENCES users(id),ai_professional_id TEXT REFERENCES ai_professionals(id),visa_status TEXT,tags TEXT NOT NULL DEFAULT '[]',status TEXT NOT NULL DEFAULT 'active',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS contacts (id TEXT PRIMARY KEY,company_id TEXT REFERENCES companies(id),name TEXT NOT NULL,email TEXT,phone TEXT,job_title TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS leads (id TEXT PRIMARY KEY,name TEXT NOT NULL,email TEXT NOT NULL,whatsapp TEXT,country TEXT NOT NULL,service TEXT NOT NULL,budget TEXT,timeline TEXT,notes TEXT,status TEXT NOT NULL DEFAULT 'new',stage TEXT NOT NULL DEFAULT 'new',assigned_consultant_id TEXT REFERENCES users(id),assigned_ai_id TEXT REFERENCES ai_professionals(id),tags TEXT NOT NULL DEFAULT '[]',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tasks (id TEXT PRIMARY KEY,title TEXT NOT NULL,description TEXT,priority TEXT NOT NULL DEFAULT 'medium',status TEXT NOT NULL DEFAULT 'todo',deadline TEXT,created_by TEXT NOT NULL REFERENCES users(id),assigned_user_id TEXT REFERENCES users(id),assigned_ai_id TEXT REFERENCES ai_professionals(id),client_id TEXT REFERENCES clients(id),company_id TEXT REFERENCES companies(id),department_id TEXT REFERENCES departments(id),parent_task_id TEXT REFERENCES tasks(id),confidence INTEGER NOT NULL DEFAULT 80,progress INTEGER NOT NULL DEFAULT 0,requires_human_review INTEGER NOT NULL DEFAULT 0,review_status TEXT NOT NULL DEFAULT 'not_required',failure_reason TEXT,completed_at TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS task_comments (id TEXT PRIMARY KEY,task_id TEXT NOT NULL REFERENCES tasks(id) ON DELETE CASCADE,user_id TEXT NOT NULL REFERENCES users(id),body TEXT NOT NULL,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS documents (id TEXT PRIMARY KEY,name TEXT NOT NULL,mime_type TEXT NOT NULL,storage_key TEXT NOT NULL,size_bytes INTEGER NOT NULL DEFAULT 0,client_id TEXT REFERENCES clients(id),company_id TEXT REFERENCES companies(id),task_id TEXT REFERENCES tasks(id),uploaded_by TEXT REFERENCES users(id),created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS invoices (id TEXT PRIMARY KEY,client_id TEXT REFERENCES clients(id),amount REAL NOT NULL,currency TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'draft',due_date TEXT,paid_at TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS activities (id TEXT PRIMARY KEY,actor_type TEXT NOT NULL,actor_id TEXT,action TEXT NOT NULL,entity_type TEXT NOT NULL,entity_id TEXT NOT NULL,metadata TEXT NOT NULL DEFAULT '{}',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS notifications (id TEXT PRIMARY KEY,user_id TEXT NOT NULL REFERENCES users(id),type TEXT NOT NULL,title TEXT NOT NULL,message TEXT NOT NULL,entity_type TEXT,entity_id TEXT,read_at TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS ai_memory (id TEXT PRIMARY KEY,ai_professional_id TEXT NOT NULL REFERENCES ai_professionals(id) ON DELETE CASCADE,category TEXT NOT NULL,content TEXT NOT NULL,importance INTEGER NOT NULL DEFAULT 1,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS countries (code TEXT PRIMARY KEY,name TEXT NOT NULL,currency TEXT NOT NULL,language TEXT NOT NULL,active INTEGER NOT NULL DEFAULT 1);
CREATE TABLE IF NOT EXISTS workflows (id TEXT PRIMARY KEY,name TEXT NOT NULL,description TEXT,department_id TEXT REFERENCES departments(id),country TEXT,priority TEXT NOT NULL DEFAULT 'medium',trigger_type TEXT NOT NULL,definition TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'draft',active INTEGER NOT NULL DEFAULT 1,created_by TEXT REFERENCES users(id),updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workflow_runs (id TEXT PRIMARY KEY,workflow_id TEXT NOT NULL REFERENCES workflows(id) ON DELETE CASCADE,client_id TEXT REFERENCES clients(id),company_id TEXT REFERENCES companies(id),status TEXT NOT NULL DEFAULT 'running',current_step_id TEXT,completed_steps INTEGER NOT NULL DEFAULT 0,remaining_steps INTEGER NOT NULL DEFAULT 0,elapsed_minutes INTEGER NOT NULL DEFAULT 0,errors TEXT NOT NULL DEFAULT '[]',ai_actions TEXT NOT NULL DEFAULT '[]',human_actions TEXT NOT NULL DEFAULT '[]',started_by TEXT REFERENCES users(id),started_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,completed_at TEXT,updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workflow_audit_logs (id TEXT PRIMARY KEY,workflow_id TEXT REFERENCES workflows(id) ON DELETE CASCADE,run_id TEXT REFERENCES workflow_runs(id) ON DELETE CASCADE,user_id TEXT REFERENCES users(id),ai_professional_id TEXT REFERENCES ai_professionals(id),action TEXT NOT NULL,old_value TEXT,new_value TEXT,notes TEXT,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY,value TEXT NOT NULL,updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_leads_status ON leads(status);
CREATE INDEX IF NOT EXISTS idx_tasks_status_deadline ON tasks(status,deadline);
CREATE INDEX IF NOT EXISTS idx_tasks_ai_status ON tasks(assigned_ai_id,status);
CREATE INDEX IF NOT EXISTS idx_notifications_user_read ON notifications(user_id,read_at);
CREATE INDEX IF NOT EXISTS idx_activities_entity ON activities(entity_type,entity_id);
